    runtime_config:      phase7b2Out.runtime_config,
    store_profile:       phase7b2Out.store_profile,
    brand_positioning:   phase7b2Out.brand_positioning,
    market_intelligence: phase7b2Out.market_intelligence || {},
    competitor_clusters: phase7b2Out.competitor_clusters || {},
    strategy_synthesis:  phase7b2Out.strategy_synthesis  || {},
    offer_architecture:  phase7b2Out.offer_architecture  || {},
    content_strategy:    phase7b2Out.content_strategy    || {},
    store_blueprint:     phase7b2Out.store_blueprint,
  },
}];

// orchestrate-phase1 — Prepare Theme Input
// Assembles Phase 7B.3 input from Phase 7B.2 Complete output.
// Passes store_blueprint + runtime_config + theme_rules to build-shopify-theme.
// Phase 10: theme_rules from build-theme-rules is included when available.
// If build-theme-rules failed (continueOnFail), theme_rules is omitted gracefully.

const phase7b2Out  = $('Phase 7B.2 Complete').first().json;
const themeRulesOut = $input.first().json;  // output from Run build-theme-rules

// Extract theme_rules if build-theme-rules succeeded
const themeRules = (themeRulesOut && themeRulesOut.theme_rules && themeRulesOut.theme_rules.status === 'PHASE_10_COMPLETE')
  ? themeRulesOut.theme_rules
  : null;

if (themeRules) {
  console.log('Prepare Theme Input: theme_rules present — pattern=' + themeRules.store_pattern);
} else {
  console.log('Prepare Theme Input: no theme_rules — build-shopify-theme will use blueprint sections');
}

const output = {
  project_id:       phase7b2Out.project_id,
  runtime_config:   phase7b2Out.runtime_config,
  store_blueprint:  phase7b2Out.store_blueprint,
  content_strategy: phase7b2Out.content_strategy,
  theme_rules:      themeRules,
};

if (!output.store_blueprint) {
  throw new Error('Prepare Theme Input: store_blueprint missing from Phase 7B.2 Complete output.');
}
if (!output.runtime_config) {
  throw new Error('Prepare Theme Input: runtime_config missing from Phase 7B.2 Complete output.');
}

console.log('Prepare Theme Input: assembled for project=' + output.project_id);
return [{ json: output }];

// orchestrate-phase1 — Phase 7B.3 Complete
// Terminal node for the full Phase 1–7B.3 chain.
// Returns all 12 artifacts inline. Top-level status reflects theme deployment result.

const phase7b2Out = $('Phase 7B.2 Complete').first().json;
const themeOut    = $('Run build-shopify-theme').first().json;

// Determine top-level status from theme deployment
const themeStatus = themeOut.status || 'PHASE_7B3_FAILED';
let topStatus;
if (themeStatus === 'PHASE_7B3_COMPLETE') topStatus = 'PHASE_7B3_COMPLETE';
else if (themeStatus === 'PHASE_7B3_PARTIAL') topStatus = 'PHASE_7B3_PARTIAL';
else if (themeStatus === 'PHASE_7B3_DRY_RUN') topStatus = 'PHASE_7B3_DRY_RUN';
else if (themeStatus === 'PHASE_7B3_BLOCKED') topStatus = 'PHASE_7B3_BLOCKED';
else topStatus = 'PHASE_7B3_FAILED';

const summary = {
  ...phase7b2Out,
  status: topStatus,
  next_phase: 'Phase 7B.4 — Store Build (theme publish)',

  shopify_theme_deployment: {
    status:           themeOut.status,
    theme_id:         themeOut.theme_id,
    theme_name:       themeOut.theme_name,
    sections_written: themeOut.sections_written,
    assets_written:   themeOut.assets_written,
    dry_run:          themeOut.dry_run,
    dry_run_plan:     themeOut.dry_run_plan || undefined,
    errors:           themeOut.errors,
    warnings:         themeOut.warnings,
    shop_url:         themeOut.shop_url,
    blueprint_summary: themeOut.blueprint_summary,
    safety_notes:     themeOut.safety_notes,
  },
};

return [{ json: summary }];

// orchestrate-phase1 — Halt: Shopify Theme Failed
// Reached when build-shopify-theme returns PHASE_7B3_FAILED.

const themeOut = $('Run build-shopify-theme').first().json;

return [{
  json: {
    status: 'HALTED',
    halted_at: 'Phase 7B.3 — Shopify Theme Deployment',
    reason: 'build-shopify-theme returned PHASE_7B3_FAILED',
    theme_deployment_status: themeOut.status,
    errors: themeOut.errors || [],
    warnings: themeOut.warnings || [],
  },
}];
